// RLS elevation log — records of elevation_scope() calls.
// Generated by flowforge JTBD generator — do not edit by hand.
import * as React from "react";

import { adminApi, type AdminRlsElevation } from "../api";

export function RlsLog(): React.ReactElement {
	const [rows, setRows] = React.useState<ReadonlyArray<AdminRlsElevation>>([]);
	const [error, setError] = React.useState<string | null>(null);
	const [busy, setBusy] = React.useState(false);
	const [showActiveOnly, setShowActiveOnly] = React.useState(false);

	const load = React.useCallback(async () => {
		setBusy(true);
		setError(null);
		try {
			setRows(await adminApi.listRlsElevations());
		} catch (e: unknown) {
			setError(e instanceof Error ? e.message : "load failed");
		} finally {
			setBusy(false);
		}
	}, []);

	React.useEffect(() => {
		void load();
	}, [load]);

	const visible = rows.filter((r) => !showActiveOnly || r.ended_at == null);

	return (
		<section aria-labelledby="rls-heading">
			<h2 id="rls-heading">RLS elevations</h2>
			<p className="ff-admin-hint">
				Every <code>elevation_scope()</code> call the host opens lands here via
				the <code>rls.elevate</code> audit topic. An open scope (no
				<code>ended_at</code>) means RLS is still bypassed for that actor —
				investigate if the duration looks unusual.
			</p>
			<form
				className="ff-admin-filters"
				onSubmit={(e) => {
					e.preventDefault();
					void load();
				}}
			>
				<label>
					<input
						type="checkbox"
						checked={showActiveOnly}
						onChange={(e) => setShowActiveOnly(e.target.checked)}
					/>{" "}
					Show only currently-open scopes
				</label>
				<button type="submit" disabled={busy}>
					{busy ? "Loading…" : "Refresh"}
				</button>
			</form>
			{error ? (
				<p role="alert" className="ff-admin-error">
					{error}
				</p>
			) : null}
			<table className="ff-admin-table">
				<thead>
					<tr>
						<th scope="col">started</th>
						<th scope="col">ended</th>
						<th scope="col">tenant</th>
						<th scope="col">actor</th>
						<th scope="col">scope</th>
						<th scope="col">reason</th>
					</tr>
				</thead>
				<tbody>
					{visible.map((row) => (
						<tr key={row.id}>
							<td>
								<time dateTime={row.started_at}>{row.started_at}</time>
							</td>
							<td>
								{row.ended_at ? (
									<time dateTime={row.ended_at}>{row.ended_at}</time>
								) : (
									<strong className="ff-admin-status ff-admin-status-active">open</strong>
								)}
							</td>
							<td>{row.tenant_id}</td>
							<td>{row.actor}</td>
							<td>
								<code>{row.scope}</code>
							</td>
							<td>{row.reason}</td>
						</tr>
					))}
					{visible.length === 0 && !busy ? (
						<tr>
							<td colSpan={6}>no elevations recorded</td>
						</tr>
					) : null}
				</tbody>
			</table>
		</section>
	);
}
